117: func (s *watchableStore) NewWatchStream() WatchStream {
118: 	watchStreamGauge.Inc()
119: 	return &watchStream{
120: 		watchable: s,
121: 		ch:        make(chan WatchResponse, chanBufLen),
122: 		cancels:   make(map[WatchID]cancelFunc),
123: 		watchers:  make(map[WatchID]*watcher),
124: 	}
125: }
